// ===== AGENT UNITE (tier list Game8) =====
const h=$('Game8 Unite').first().json.data;
let prev=null; try{ prev=$('Veille unite').first().json; }catch(e){}
const strip=s=>String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const now=new Date(), iso=now.toISOString();
const seed=now.getDate()+now.getMonth()*31;
const noise=/^(Top|Bot|Bottom|Jungle|boosted attacks|dash|ganking|vision|Attack|Held Items|Defenders?|Attackers?|Supporter|Speedster|All-Rounder|Sprint mechanic|objectives|Version)/i;
const tiers={};
for(const s of String(h).matchAll(/<h3[^>]*>\s*(OP|SS|S|A|B|C) Tier\s*<\/h3>([\s\S]*?)(?=<h3|$)/g)){
  tiers[s[1]]=[...new Set([...s[2].matchAll(/<a[^>]*>([^<]{2,24})<\/a>/g)].map(m=>strip(m[1]))
    .filter(n=>n&&!noise.test(n)&&/^[A-Z]/.test(n)&&!/Tier List|List$/.test(n)))];
}
const sNow=[...(tiers.OP||[]),...(tiers.SS||[])];
if(!sNow.length) throw new Error('Parseur Unite KO — structure Game8 changée ?');
const tPrev=(prev&&prev.tierList)||{};
const sPrev=tPrev.S||[];
const inS=sNow.filter(n=>!sPrev.includes(n)), outS=sPrev.filter(n=>!sNow.includes(n));
const summary=(inS.length||outS.length)
 ? "Tier list Game8 mise à jour : "+(inS.length?inS.join(', ')+" rejoint le sommet":"")+(inS.length&&outS.length?" · ":"")+(outS.length?outS.join(', ')+" en sort":"")+"."
 : "Tier list stable — "+sNow.slice(0,5).join(', ')+" tiennent le sommet. Zoom du jour : "+sNow[seed%sNow.length]+".";
const out=Object.assign({},prev||{},{
 tierList:Object.assign({},tPrev,{S:sNow,'A+':tiers.S||tPrev['A+']||[],A:tiers.A||tPrev.A||[],B:tiers.B||tPrev.B||[],C:tiers.C||tPrev.C||[]}),
 metaSummary:summary, updatedAt:iso});
return [{json:{content:JSON.stringify(out,null,2),msg:"bot(unite) "+now.toLocaleDateString('fr-FR')+" : "+(inS.length+outS.length?inS.length+outS.length+" changements tier S":"stable, zoom "+sNow[seed%sNow.length])}}];
